import { useState } from "react";
import { motion } from "framer-motion";
import { useNavigate } from "react-router-dom";
import axios from "axios";

/* ===============================
   🎨 DESIGN VARIABLES
================================= */

const styles = {
  colors: {
    primary: "bg-indigo-600",
    primaryHover: "hover:bg-indigo-700",
    background: "bg-gradient-to-br from-slate-900 to-slate-800",
    card: "bg-white/10 backdrop-blur-lg",
    textPrimary: "text-white",
    textSecondary: "text-gray-300",
    inputBg: "bg-white/20",
    inputBorder: "border-white/30",
  },
  spacing: {
    container: "min-h-screen flex items-center justify-center px-4",
    card: "w-full max-w-md p-8 rounded-2xl shadow-2xl",
    input: "w-full p-3 rounded-lg border outline-none",
    button: "w-full py-3 rounded-lg font-semibold transition duration-300",
  },
  animation: {
    container: {
      initial: { opacity: 0 },
      animate: { opacity: 1 },
      transition: { duration: 0.6 },
    },
    card: {
      initial: { y: 40, opacity: 0 },
      animate: { y: 0, opacity: 1 },
      transition: { duration: 0.6 },
    },
  },
};

/* ===============================
   🚀 COMPONENT
================================= */

const AdminLogin = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    email: "",
    password: "",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const { data } = await axios.post("/api/users/login", form);

      if (data.role !== "admin") {
        setError("You are not authorized as Admin");
        setLoading(false);
        return;
      }

      localStorage.setItem("adminInfo", JSON.stringify(data));
      navigate("/admin/dashboard");
    } catch (err) {
      setError("Invalid email or password");
    }

    setLoading(false);
  };

  return (
    <motion.div
      {...styles.animation.container}
      className={`${styles.colors.background} ${styles.spacing.container}`}
    >
      <motion.div
        {...styles.animation.card}
        className={`${styles.colors.card} ${styles.spacing.card}`}
      >
        <h2
          className={`text-3xl font-bold text-center mb-6 ${styles.colors.textPrimary}`}
        >
          Admin Login
        </h2>

        {error && (
          <p className="text-red-400 text-sm mb-4 text-center">
            {error}
          </p>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            type="email"
            name="email"
            placeholder="Admin Email"
            value={form.email}
            onChange={handleChange}
            required
            className={`${styles.spacing.input} ${styles.colors.inputBg} ${styles.colors.inputBorder} ${styles.colors.textPrimary}`}
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
            required
            className={`${styles.spacing.input} ${styles.colors.inputBg} ${styles.colors.inputBorder} ${styles.colors.textPrimary}`}
          />

          <button
            type="submit"
            disabled={loading}
            className={`${styles.spacing.button} ${styles.colors.primary} ${styles.colors.primaryHover} text-white`}
          >
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>
      </motion.div>
    </motion.div>
  );
};

export default AdminLogin;
